
'use client';

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Bus, MapPin, Bell, User, MessageSquare } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { WelcomeHeader } from "@/components/dashboard/welcome-header";
import Image from "next/image";

const children = [
    { name: 'Alice', status: 'On Bus', route: 'North Route', bus: 'Bus 101', eta: '5 min' },
    { name: 'Bob', status: 'Dropped Off', route: 'North Route', bus: 'Bus 101', eta: '-' }
];

const alerts = [
    { time: '8:10 AM', message: 'Bus 101 is running 5 minutes late due to traffic.' },
    { time: '7:45 AM', message: 'Alice has been picked up.' }
];

export default function ParentDashboardPage() {
  const { toast } = useToast();

  const handleContactDriver = (childName: string) => {
    toast({
        title: "Contacting Driver",
        description: `A message has been sent to the driver regarding ${childName}. They will respond when it is safe to do so.`,
    })
  }

  return (
    <div className="space-y-8">
      <WelcomeHeader user="Parent" name="Parent User" />

      <div className="grid gap-8 lg:grid-cols-3">
        <div className="lg:col-span-2">
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2"><Bus className="h-5 w-5 text-primary" /> Live Bus Tracking</CardTitle>
                    <CardDescription>Bus 101 is currently on the North Route.</CardDescription>
                </CardHeader>
                <CardContent>
                    <div className="aspect-video bg-muted rounded-lg overflow-hidden">
                        <Image
                            src="https://placehold.co/800x450.png"
                            alt="A map showing a bus location"
                            width={800}
                            height={450}
                            className="w-full h-full object-cover"
                            data-ai-hint="map bus"
                          />
                    </div>
                </CardContent>
            </Card>
        </div>
        
        <div className="space-y-8">
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2"><Bell className="h-5 w-5 text-primary" /> Real-time Alerts</CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="space-y-4">
                        {alerts.map((alert, index) => (
                            <div key={index} className="flex items-start gap-3">
                                <div className="text-xs font-semibold text-muted-foreground pt-1">{alert.time}</div>
                                <div className="flex-1 text-sm">{alert.message}</div>
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>
        </div>
      </div>

       <Card>
        <CardHeader>
            <CardTitle className="flex items-center gap-2"><User className="h-5 w-5 text-primary" /> My Children</CardTitle>
        </CardHeader>
        <CardContent className="grid gap-6 sm:grid-cols-1 lg:grid-cols-2">
            {children.map((child) => (
                 <Card key={child.name} className="flex flex-col sm:flex-row items-start gap-4 p-4">
                    <Avatar className="h-16 w-16">
                        <AvatarImage src={`https://placehold.co/64x64.png`} data-ai-hint="child portrait"/>
                        <AvatarFallback>{child.name.charAt(0)}</AvatarFallback>
                    </Avatar>
                    <div className="flex-1 space-y-2">
                        <div className="flex items-center justify-between">
                            <h3 className="text-lg font-semibold">{child.name}</h3>
                             <Badge variant={child.status === 'On Bus' ? 'default' : 'secondary'} className={child.status === 'On Bus' ? 'bg-green-500 text-white' : ''}>
                                {child.status}
                            </Badge>
                        </div>
                        <p className="text-sm text-muted-foreground flex items-center gap-2">
                            <MapPin className="h-4 w-4" /> {child.route} ({child.bus})
                        </p>
                        <p className="text-sm font-medium">
                            {child.status === 'On Bus' ? `ETA to your stop: ${child.eta}` : 'Journey complete for today.'}
                        </p>
                    </div>
                    <Button variant="ghost" size="icon" className="absolute top-2 right-2 sm:static" onClick={() => handleContactDriver(child.name)}>
                        <MessageSquare className="h-4 w-4"/>
                        <span className="sr-only">Contact Driver</span>
                    </Button>
                </Card>
            ))}
        </CardContent>
      </Card>
    </div>
  )
}
